def score_many(rows):
    rows = [[float(v) for v in r] for r in rows]
    k = len(rows)
    if k == 0:
        return []
    n = 46
    mean = [0.0]*n; mx = [-1e30]*n
    for r in rows:
        for j in range(n):
            mean[j] += r[j]
            if r[j] > mx[j]: mx[j] = r[j]
    for j in range(n): mean[j] /= k
    out = []
    for r in rows:
        x = r + mean + mx  # 138
        z = [(x[i]-MEAN[i])/STD[i] for i in range(len(x))]
        for li in range(_NL):
            W = globals()['W%d'%li]; B = globals()['B%d'%li]
            o = []
            for rr in range(len(W)):
                row = W[rr]; acc = B[rr]
                for c in range(len(row)): acc += row[c]*z[c]
                o.append(acc)
            if li < _NL-1:
                o = [v if v>0.0 else 0.0 for v in o]
            z = o
        out.append(z[0])
    return out
